: $host\\\"\';\\n\\n    access_log  /logs/access.log  main;    \\n\\n    upstream local{\\n        server 127.0.0.1:8080;\\n        keepalive 64;\\n    }\\n\\n}\", \"mount_path\": \"/etc/nginx/nginx.conf\", \"base64_encoded\": false}, {\"content\": \"\\nserver {\\n        listen 80;\\n\\n    location = / {\\n        access_log off;\\n        return  http://127.0.0.1:10801$request_uri;\\n    }\\n\\n    location / {\\n        proxy_redirect off;\\n        proxy_set_header Host $http_host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass http://127.0.0.1:18081$request_uri;\\n    }\\n\\t\\t\\n    error_page  404 403 500 502 503 504  /tunnel_error.html;\\n    location = /tunnel_error.html {\\n         root   /macc/data/staticsite/errors/;\\n    }\\n}\", \"mount_path\": \"/etc/nginx/conf.d/tunnel-mgt.conf\", \"base64_encoded\": false}, {\"content\": \"\\nserver {\\n        listen 443 ssl;\\n#        server_name _;\\n\\n        ssl_certificate /etc/nginx/tls/tls.crt;\\n        ssl_certificate_key /etc/nginx/tls/tls.key;\\n        ssl_protocols TLSv1.2 TLSv1.3;\\n        ssl_prefer_server_ciphers on;\\n\\n        # 处理器使用VPC网关的第三个地址（用作DNS的保留地址）\\n#        resolver 10.135.0.2;\\n\\n        server_name \\\"~^[1-9d-k]{1}([1-9]{1})([0-9]{1})[0-9]{1}([0-9]{2})([0-9]{1})[0-9]{1}([s]?)[h-r]{1}([a-q]{1})\\\\..*$\\\";\\n                set $tunnel_port $1$4$3$2;\\n                set $tunnel_protocol $5;\\n                set $host_alias $6;\\n\\n\\n        # 最大参数体限制\\n        client_max_body_size 300m;\\n        # 最大连接时间限制\\n        proxy_connect_timeout 300;\\n        # 最大发送请求超时时间限制\\n        proxy_send_timeout 300;\\n        proxy_read_timeout 300;\\n\\n        location / {\\n            proxy_redirect off;\\n            proxy_request_buffering off;\\n            proxy_http_version 1.1;\\n            proxy_set_header Connection \\\"\\\";\\n            proxy_set_header Cookie $http_cookie;\\n            proxy_set_header Accept-Encoding \\\"gzip, deflate, sdch\\\";\\n            proxy_set_header Host $http_host;\\n            client_max_body_size 300m;\\n            proxy_buffering off;\\n\\n#             set $proxy_full_url http$tunnel_protocol://tunnel-$host_alias.cloud.io:$tunnel_port$request_uri;\\n#             proxy_pass $proxy_full_url;\\n            if ( $host_alias = \\\"a\\\"){\\n                set $proxy_full_url 443http$tunnel_protocol://127.0.0.1:$tunnel_port$request_uri;\\n                proxy_pass http$tunnel_protocol://127.0.0.1:$tunnel_port$request_uri;\\n            }\\n#            if ( $host_alias = \\\"b\\\"){\\n#                set $proxy_full_url 443http$tunnel_protocol://10.135.11.61:$tunnel_port$request_uri;\\n#                proxy_pass http$tunnel_protocol://10.135.11.61:$tunnel_port$request_uri;\\n#            }\\n\\n#            set $host_alias error443;\\n#            proxy_pass http://local;\\n        }\\n\\n        error_page  404 403 500 502 503 504  /tunnel_error.html;\\n        location = /tunnel_error.html {\\n             root   /macc/data/staticsite/errors/;\\n        }\\n}\", \"mount_path\": \"/etc/nginx/conf.d/tunnel-ssh.conf\", \"base64_encoded\": false}, {\"content\": \"\\n<!DOCTYPE html>\\n<html>\\n<head>\\n<meta charset=\\\"utf-8\\\">\\n<base href=\\\"${cxt}/${I18N[base.lang]}/\\\" />\\n<meta http-equiv=\\\"X-UA-Compatible\\\" content=\\\"IE=edge\\\">\\n<meta name=\\\"viewport\\\" content=\\\"initial-scale=1.0\\\">\\n<style type=\\\"text/css\\\">\\n\\t.contant{\\n\\t\\tfont-family: Lato,Helvetica Neue,Helvetica,Arial,sans-serif;\\n\\t\\tmargin-top: 3.19rem;\\n\\t\\tmargin-left: 4.31rem;\\n\\t}\\n\\t.errimg{\\n\\t\\tbackground: url(\'data:image/png;base64,\') no-repeat;\\n\\t\\tbackground-size: cover;\\n\\t\\twidth: 4.82rem;\\n\\t    height: 3.78rem;\\n\\t    display: inline-block;\\n\\t}\\n\\t.letters{\\n\\t\\tdisplay: inline-block;\\n\\t\\tvertical-align: top;\\n\\t}\\n\\t.oops{\\n\\t\\tfont-size: .56rem;\\n\\t\\tmargin-top: .8rem;\\n\\t\\tline-height: .78rem;\\n\\t}\\n\\t.domain{\\n\\t\\tfont-size: .3rem;\\n\\t\\tmargin-top: .08rem;\\n\\t}\\n\\t@media (max-width: 768px) {\\n\\t\\t.contant {\\n\\t\\t    width: 80%;\\n\\t\\t    margin: 1.5rem auto;\\n\\t\\t}\\n\\t\\t.errimg{\\n\\t\\t    display: block;\\n\\t\\t    margin: auto;\\n\\t\\t}\\n\\t}\\n</style>\\n</head>\\n<body>\\n\\t<div class=\\\"contant\\\">\\n\\t\\t<div class=\\\"errimg\\\"></div>\\n\\t\\t<div class=\\\"letters\\\">\\n\\t\\t\\t<div class=\\\"oops\\\">Oops!</div>\\n\\t\\t\\t<div class=\\\"domain\\\">The tunnel has expired. Please create the tunnel again. </div>\\n\\t\\t</div>\\n\\t</div>\\n\\t\\t<script type=\\\"text/javascript\\\">\\n\\t\\t//设置顶级fontsize作为基础值\\n\\t\\t(function (doc, win) {\\n          var docEl = doc.documentElement,//根元素html\\n          //判断窗口有没有orientationchange这个方法，有就赋值给一个变量，没有就返回resize方法。\\n            resizeEvt = \'orientationchange\' in window ? \'orientationchange\' : \'resize\',\\n            recalc = function () {\\n              var clientWidth = docEl.clientWidth;\\n              if (!clientWidth) return;\\n              //把document的fontSize大小设置成跟窗口成一定比例的大小，从而实现响应式效果。\\n              if(clientWidth > 1023){\\n\\t\\t      \\tdocEl.style.fontSize = 20 * (clientWidth / 384) + \'px\';\\n\\t\\t      }else if(clientWidth < 1024 && clientWidth > 769){\\n\\t\\t      \\tdocEl.style.fontSize = 20 * (clientWidth / 384) + \'px\';\\n\\t\\t      }else{\\n\\t\\t      \\tdocEl.style.fontSize = 50 * (clientWidth / 384) + \'px\';\\n\\t\\t      }\\n            };\\n            //alert(docEl)\\n          if (!doc.addEventListener) return;\\n          win.addEventListener(resizeEvt, recalc, false);//addEventListener事件方法接受三个参数：第一个是事件名称比如点击事件onclick，第二个是要执行的函数，第三个是布尔值\\n          doc.addEventListener(\'DOMContentLoaded\', recalc, false)//绑定浏览器缩放与加载时间\\n          recalc();\\n        })(document, window);\\n\\t</script>\\n</body>\\n</html>\", \"mount_