ow=|\\norg.apache.el.GET_CLASSLOADER_USE_PRIVILEGED=false\", \"mount_path\": \"/usr/local/tomcat/conf/catalina.properties\", \"base64_encoded\": false}, {\"content\": \"<?xml version=\\\"1.0\\\" encoding=\\\"UTF-8\\\"?>\\n<!--\\n  Licensed to the Apache Software Foundation (ASF) under one or more\\n  contributor license agreements.  See the NOTICE file distributed with\\n  this work for additional information regarding copyright ownership.\\n  The ASF licenses this file to You under the Apache License, Version 2.0\\n  (the \\\"License\\\"); you may not use this file except in compliance with\\n  the License.  You may obtain a copy of the License at\\n\\n      http://www.apache.org/licenses/LICENSE-2.0\\n\\n  Unless required by applicable law or agreed to in writing, software\\n  distributed under the License is distributed on an \\\"AS IS\\\" BASIS,\\n  WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\\n  See the License for the specific language governing permissions and\\n  limitations under the License.\\n-->\\n<!-- The contents of this file will be loaded for each web application -->\\n<Context>\\n    <Resources allowLinking=\\\"true\\\" />\\n\\n    <!-- Default set of monitored resources. If one of these changes, the    -->\\n    <!-- web application will be reloaded.                                   -->\\n    <WatchedResource>WEB-INF/web.xml</WatchedResource>\\n    <WatchedResource>${catalina.base}/conf/web.xml</WatchedResource>\\n\\n    <Loader delegate=\\\"true\\\" />\\n    <!-- Uncomment this to disable session persistence across Tomcat restarts -->\\n    <!--\\n    <Manager pathname=\\\"\\\" />\\n    -->\\n</Context>\", \"mount_path\": \"/usr/local/tomcat/conf/context.xml\", \"base64_encoded\": false}], \"image_source\": {\"mode\": \"custom\", \"customImage\": \"cloud-docker-register-registry.cn-hangzhou.cr.aliyuncs.com/sbg/macc-service:20260609-196817-ack\"}, \"limit_memory\": \"4Gi\", \"writable_dirs\": [{\"mode\": \"\", \"mount_path\": \"/etc/config\", \"size_limit\": \"\", \"owner_group\": \"\"}, {\"mode\": \"\", \"mount_path\": \"/macc\", \"size_limit\": \"\", \"owner_group\": \"\"}, {\"mode\": \"\", \"mount_path\": \"/app/config-cache\", \"size_limit\": \"\", \"owner_group\": \"\"}], \"liveness_probe\": {\"path\": \"/service/ruok\", \"port\": 8080, \"type\": \"http\", \"enabled\": true, \"period_seconds\": 10, \"timeout_seconds\": 10, \"failure_threshold\": 3, \"success_threshold\": 1, \"initial_delay_seconds\": 90}, \"readiness_probe\": {\"path\": \"/service/ruok\", \"port\": 8080, \"type\": \"http\", \"enabled\": true, \"period_seconds\": 5, \"timeout_seconds\": 10, \"failure_threshold\": 5, \"success_threshold\": 1, \"initial_delay_seconds\": 30}}], \"terminationGracePeriodSeconds\": 60}','2026-06-29 11:11:37.969173','2026-06-29 20:15:55.481634');
INSERT INTO `workload_stage_configs` (`id`, `tenant_id`, `project_id`, `application_id`, `workload_id`, `stage_key`, `replicas`, `network_mode`, `service_ports_json`, `resource_requests_json`, `resource_limits_json`, `probes_json`, `ingress_hosts_json`, `env_vars_json`, `secret_refs_json`, `config_files_json`, `writable_dirs_json`, `volume_mounts_json`, `init_containers_json`, `values_override_json`, `created_at`, `updated_at`) VALUES ('workload_stage_config_f77e3ujtp6avhypeaxjh3vel2q','tenant_sbg','project_macc','app_nnb4pz5qp7rsy6cobjiuz32pwy','workload_onf4n676x22wkhldbmxwfk4uum','dev',2,'container','null','{\"cpu\": \"50m\", \"memory\": \"64Mi\"}','{\"cpu\": \"1\", \"memory\": \"2Gi\"}','null','[{\"tls\": true, \"host\": \"cloud-ltt.rj.link\", \"path\": \"/\", \"rewrite_path\": \"/\", \"tls_redirect\": true}]','null','null','[{\"content\": \"\\nuser              nginx;\\nworker_processes  4;\\nworker_rlimit_nofile 1500;\\n\\nerror_log  /logs/nginx/error.log;\\n\\npid        /var/run/nginx.pid;\\n\\n\\nevents {\\n    worker_connections  10240;\\n}\\n\\n\\nhttp {\\n    include       /etc/nginx/mime.types;\\n    default_type  application/octet-stream;\\n\\n    log_format  main  \'$remote_addr - $remote_user [$time_local] \\\"$request\\\" \'\\n                      \'$status $body_bytes_sent \\\"$http_referer\\\" \'\\n                      \'\\\"$http_user_agent\\\" \\\"$http_x_forwarded_for\\\" $request_length $http_host -$request_time sec\';\\n     access_log  /logs/nginx/access.log  main;\\n     sendfile on;\\n     tcp_nopush on;\\n     tcp_nodelay on;\\n     keepalive_timeout 65;\\n     types_hash_max_size 2048;\\n   \\n     gzip on;\\n     gzip_min_length 2k;\\n     gzip_buffers 4 16k;\\n     gzip_comp_level 2;\\n     gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript image/jpeg image/gif image/png;\\n     gzip_vary on;\\n     gzip_proxied any;\\n    proxy_intercept_errors on;\\n    include /etc/nginx/conf.d/*.conf;\\n\\n}\", \"mount_path\": \"/etc/nginx/nginx.conf\"}, {\"content\": \"\\nserver {\\n        listen 80 default_server;\\n        listen [::]:80 default_server;\\n        server_name as_front;\\n        root /usr/share/nginx/html;\\n        # Load configuration files for the default server block.\\n\\n        set $cloudapi_endpoint http://cloudapi.cloud.io;\\n        set $node_endpoint http://node.cloud.io;\\n        set $enet_design_endpoint http://enet.cloud.io;\\n        set $emu_endpoint http://emu.cloud.io:8090;\\n        set $request_filter $request;\\n        if ($request_filter ~ (.*passwor[dt]=)[^&]*(.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*passwor[dt]%22%3A%22).*?(%22.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*account=)[^&]*(.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*account%22%3A%22).*?(%22.*)) {\\n            set $request_filter $1******$2;\\n        }\\n\\n        # include /etc/nginx/default.d/*.conf;\\n        # include /etc/nginx/static/*.conf;\\n        location /error {\\n            alias /macc/install/tomcat/webapps/admin3/websrc/pages/base/error;\\n        }\\n   \\n       \\n    # 体验网络demo后台\\n    location ~ ^/emu/(.*) {\\n        # 允许特定 IP 访问\\n        #allow 34.87.31.116;      # 亚洲GCP\\n        #allow 35.198.241.205;    # 亚洲GCP\\n        #allow 3.122.133.112;     # 欧洲AWS\\n        #allow 3.138.253.188;     # 美国AWS\\n        #allow 8.219.0.173;    #亚洲Aliyun\\n        # 拒绝所有其他 IP\\n        #deny all;\\n\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_pass $emu_endpoint/$1$is_args$args;\\n        #proxy_pass http://emu.cloud.io/$1$is_args$args;\\n    }\\n        #cx node\\n    location /cx/ {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        client_max_body_size 128m;\\n        proxy_pass $node_endpoint;\\n    }\\n\\n    location  ^~ /api/v1 {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_pass  $enet_design_endpoint$request_uri;\\n        client_max_body_size    128m;\\n    }\\n\\n    location /admin3/register {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        rewrite ^(.*) https://$host$1 permanent;\\n    }\\n\\n    location = /favicon.ico {\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n\\n\\n    location = / {\\n        return 302 /macc5/admin/;\\n    }\\n\\n    #极速开局\\n    location /sceneConfAdmin2/ {\\n        client_max_body_size 50m;\\n        proxy_set_header Host $http_host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_set_header X-Forwarded-Proto https;\\n        proxy_pass http://127.0.0.1:8080/sceneConfAlphaAdmin2/;\\n    }\\n\\n    #极速开局\\n    location /sceneConfAlphaAdmin2 {\\n        client_max_body_size 50m;\\n        proxy_set_header Host $http_host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_set_header X-Forwarded-Proto https;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n      \\n\\n    #SSO和admin3\\n    location ~* ^/(admin3|sso) {\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n        \\n    location /admin3/maintenance/uploadFirmware {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_request_buffering off;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass http://127.0.0.1:8080$request_uri;\\n    }\\n        \\n        #领航员\\n    location ~ ^/bidah5 {\\n        proxy_redirect off;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header X-Forwarded-Proto  $scheme;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint$request_uri;\\n    }\\n\\n    # 静态文件\\n    location ~ ^/macc5/adminIntl/static/(.*)$ {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint/bidah5/static/$1;\\n    }\\n\\n    location ~ ^/macc5/isp/static/(.*)$ {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint/bidah5/static/$1;\\n    }\\n\\n    #macc 5\\n    location /macc5 {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /usr/share/nginx/html/macc5/;\\n        if ($request_filename ~* .*\\\\.html$) {\\n            add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n\\n    location ^~ /webproxy {\\n        client_max_body_size 500m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n#       proxy_max_temp_file_size 0; # 禁止使用临时文件“解决图片加载失败的问题”\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /rview {\\n        client_max_body_size 500m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n            proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        #       proxy_max_temp_file_size 0; # 禁止使用临时文件“解决图片加载失败的问题”\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /cloudcontroller {\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /firewall {\\n            add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /usr/share/nginx/html/firewall/;\\n        if ($request_filename ~* .*\\\\.html$) {\\n            add_header Cache-Control no-store;\\n        }\\n\\n        index index.html;\\n    }\\n\\n    location /bida6 {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/bida6/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    } \\n    \\n    location /macc6 {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/macc6/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n    \\n    location /frontcomponents {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/frontcomponents/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n    \\n    location /sefirewall {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/sefirewall/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n\\n    location ^~ /characteristic/ {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /macc/data/characteristic/;\\n        sendfile on;\\n        autoindex on;\\n    }\\n\\n    # 海外前端 nginx 新增配置轮播图\\n    location ^~ /nocstats {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /macc/data/staticsite/nocstats;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n            add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n       \\n    location ^~ /3rdservice/ {\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass $cloudapi_endpoint;\\n    }\\n\\n    error_page 401 404 405 406 407 500 501 502 503 504 /serverstatus.html;\\n    location = /index.html {\\n        root /usr/share/nginx/html;\\n    }\\n\\n}\", \"mount_path\": \"/etc/nginx/conf.d/macc_http.conf\"}, {\"content\": \"\\n<html>\\n<head><meta http-equiv=\\\"refresh\\\" content=\\\"0;url=/macc5/admin\\\">\\n<title></title>\\n</head>\\n<body></body>\\n</html>\", \"mount_path\": \"/usr/share/nginx/html/index.html\"}]','null','null','null','{\"containers\": [{\"cpu\": \"50m\", \"name\": \"frontend\", \"memory\": \"64Mi\", \"env_vars\": [], \"limit_cpu\": \"1\", \"secret_refs\": [], \"config_files\": [{\"content\": \"\\nuser              nginx;\\nworker_processes  4;\\nworker_rlimit_nofile 1500;\\n\\nerror_log  /logs/nginx/error.log;\\n\\npid        /var/run/nginx.pid;\\n\\n\\nevents {\\n    worker_connections  10240;\\n}\\n\\n\\nhttp {\\n    include       /etc/nginx/mime.types;\\n    default_type  application/octet-stream;\\n\\n    log_format  main  \'$remote_addr - $remote_user [$time_local] \\\"$request\\\" \'\\n                      \'$status $body_bytes_sent \\\"$http_referer\\\" \'\\n                      \'\\\"$http_user_agent\\\" \\\"$http_x_forwarded_for\\\" $request_length $http_host -$request_time sec\';\\n     access_log  /logs/nginx/access.log  main;\\n     sendfile on;\\n     tcp_nopush on;\\n     tcp_nodelay on;\\n     keepalive_timeout 65;\\n     types_hash_max_size 2048;\\n   \\n     gzip on;\\n     gzip_min_length 2k;\\n     gzip_buffers 4 16k;\\n     gzip_comp_level 2;\\n     gzip_types text/plain application/javascript application/x-javascript text/css application/xml text/javascript image/jpeg image/gif image/png;\\n     gzip_vary on;\\n     gzip_proxied any;\\n    proxy_intercept_errors on;\\n    include /etc/nginx/conf.d/*.conf;\\n\\n}\", \"mount_path\": \"/etc/nginx/nginx.conf\"}, {\"content\": \"\\nserver {\\n        listen 80 default_server;\\n        listen [::]:80 default_server;\\n        server_name as_front;\\n        root /usr/share/nginx/html;\\n        # Load configuration files for the default server block.\\n\\n        set $cloudapi_endpoint http://cloudapi.cloud.io;\\n        set $node_endpoint http://node.cloud.io;\\n        set $enet_design_endpoint http://enet.cloud.io;\\n        set $emu_endpoint http://emu.cloud.io:8090;\\n        set $request_filter $request;\\n        if ($request_filter ~ (.*passwor[dt]=)[^&]*(.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*passwor[dt]%22%3A%22).*?(%22.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*account=)[^&]*(.*)) {\\n            set $request_filter $1******$2;\\n        }\\n        if ($request_filter ~ (.*account%22%3A%22).*?(%22.*)) {\\n            set $request_filter $1******$2;\\n        }\\n\\n        # include /etc/nginx/default.d/*.conf;\\n        # include /etc/nginx/static/*.conf;\\n        location /error {\\n            alias /macc/install/tomcat/webapps/admin3/websrc/pages/base/error;\\n        }\\n   \\n       \\n    # 体验网络demo后台\\n    location ~ ^/emu/(.*) {\\n        # 允许特定 IP 访问\\n        #allow 34.87.31.116;      # 亚洲GCP\\n        #allow 35.198.241.205;    # 亚洲GCP\\n        #allow 3.122.133.112;     # 欧洲AWS\\n        #allow 3.138.253.188;     # 美国AWS\\n        #allow 8.219.0.173;    #亚洲Aliyun\\n        # 拒绝所有其他 IP\\n        #deny all;\\n\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_pass $emu_endpoint/$1$is_args$args;\\n        #proxy_pass http://emu.cloud.io/$1$is_args$args;\\n    }\\n        #cx node\\n    location /cx/ {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        client_max_body_size 128m;\\n        proxy_pass $node_endpoint;\\n    }\\n\\n    location  ^~ /api/v1 {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_pass  $enet_design_endpoint$request_uri;\\n        client_max_body_size    128m;\\n    }\\n\\n    location /admin3/register {\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        rewrite ^(.*) https://$host$1 permanent;\\n    }\\n\\n    location = /favicon.ico {\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n\\n\\n    location = / {\\n        return 302 /macc5/admin/;\\n    }\\n\\n    #极速开局\\n    location /sceneConfAdmin2/ {\\n        client_max_body_size 50m;\\n        proxy_set_header Host $http_host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_set_header X-Forwarded-Proto https;\\n        proxy_pass http://127.0.0.1:8080/sceneConfAlphaAdmin2/;\\n    }\\n\\n    #极速开局\\n    location /sceneConfAlphaAdmin2 {\\n        client_max_body_size 50m;\\n        proxy_set_header Host $http_host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_set_header X-Forwarded-Proto https;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n      \\n\\n    #SSO和admin3\\n    location ~* ^/(admin3|sso) {\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n        \\n    location /admin3/maintenance/uploadFirmware {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_request_buffering off;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass http://127.0.0.1:8080$request_uri;\\n    }\\n        \\n        #领航员\\n    location ~ ^/bidah5 {\\n        proxy_redirect off;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header X-Forwarded-Proto  $scheme;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint$request_uri;\\n    }\\n\\n    # 静态文件\\n    location ~ ^/macc5/adminIntl/static/(.*)$ {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint/bidah5/static/$1;\\n    }\\n\\n    location ~ ^/macc5/isp/static/(.*)$ {\\n        proxy_redirect off;\\n        client_max_body_size 200m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_set_header Cookie $http_cookie;\\n        proxy_pass $enet_design_endpoint/bidah5/static/$1;\\n    }\\n\\n    #macc 5\\n    location /macc5 {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /usr/share/nginx/html/macc5/;\\n        if ($request_filename ~* .*\\\\.html$) {\\n            add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n\\n    location ^~ /webproxy {\\n        client_max_body_size 500m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n    proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n#       proxy_max_temp_file_size 0; # 禁止使用临时文件“解决图片加载失败的问题”\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /rview {\\n        client_max_body_size 500m;\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n            proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        #       proxy_max_temp_file_size 0; # 禁止使用临时文件“解决图片加载失败的问题”\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /cloudcontroller {\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass http://127.0.0.1:8080;\\n    }\\n    location ^~ /firewall {\\n            add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /usr/share/nginx/html/firewall/;\\n        if ($request_filename ~* .*\\\\.html$) {\\n            add_header Cache-Control no-store;\\n        }\\n\\n        index index.html;\\n    }\\n\\n    location /bida6 {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/bida6/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    } \\n    \\n    location /macc6 {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/macc6/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n    \\n    location /frontcomponents {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/frontcomponents/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n    \\n    location /sefirewall {\\n       add_header \'Access-Control-Allow-Origin\' *;\\n            add_header \'Access-Control-Allow-Credentials\' \'true\';\\n            add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n            add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /usr/share/nginx/html/sefirewall/;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n                        add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n\\n    location ^~ /characteristic/ {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias /macc/data/characteristic/;\\n        sendfile on;\\n        autoindex on;\\n    }\\n\\n    # 海外前端 nginx 新增配置轮播图\\n    location ^~ /nocstats {\\n        add_header \'Access-Control-Allow-Origin\' *;\\n        add_header \'Access-Control-Allow-Credentials\' \'true\';\\n        add_header \'Access-Control-Allow-Headers\' \'Authorization,Content-Type,Accept,Origin,User-Agent,DNT,Cache-Control,X-Mx-ReqToken,X-Requested-With\';\\n        add_header \'Access-Control-Allow-Methods\' \'GET,POST,OPTIONS,PUT,DELETE\';\\n        alias    /macc/data/staticsite/nocstats;\\n        if ( $request_filename  ~* .*\\\\.html$ ) {\\n            add_header Cache-Control no-store;\\n        }\\n        index index.html;\\n    }\\n       \\n    location ^~ /3rdservice/ {\\n        proxy_set_header Host $host;\\n        proxy_set_header X-Real-IP $remote_addr;\\n        proxy_set_header X-Forwarded-For  $proxy_add_x_forwarded_for;\\n        proxy_http_version 1.1;\\n        proxy_set_header Connection \\\"\\\";\\n        proxy_pass $cloudapi_endpoint;\\n    }\\n\\n    error_page 401 404 405 406 407 500 501 502 503 504 /serverstatus.html;\\n    location = /index.html {\\n        root /usr/share/nginx/html;\\n    }\\n\\n}\", \"mount_path\": \"/etc/nginx/conf.d/macc_http.conf\"}, {\"content\": \"\\n<html>\\n<head><meta http-equiv=\\\"refresh\\\" content=\\\"0;url=/macc5/admin\\\">\\n<title></title>\\n</head>\\n<body></body>\\n</html>\", \"mount_path\": \"/usr/share/nginx/html/index.html\"}], \"limit_memory\": \"2Gi\"}, {\"cpu\": \"5m\", \"name\": \"backend\", \"memory\": \"256Mi\", \"env_vars\": [{\"name\": \"CATALINA_OPTS\", \"value\": \"-Xms2560m -Xmx3072m -Dfile.encoding=UTF-8 -Duser.timezone=Asia/Shanghai -Djava.net.preferIPv4Stack=true -XX:+HeapDumpOnOutOfMemoryError -XX:HeapDumpPath=/logs -Duser.home=/etc/config -Dcsp.sentinel.log.dir=/logs/csp -Xloggc:/logs/gc-macc.log -XX:+PrintGCDetails -Djava.net.preferIPv4Stack=true\"}], \"limit_cpu\": \"2\", \"secret_refs\": [], \"config_files\": [{\"content\": \"# Licensed to the Apache Software Foundation (ASF) under one or more\\n# contributor license agreements.  See the NOTICE file distributed with\\n# this work for additional information regarding copyright ownership.\\n# The ASF licenses this file to You under the Apache License, Version 2.0\\n# (the \\\"License\\\"); you may not use this file except in compliance with\\n# the License.  You may obtain a copy of the License at\\n#\\n#     http://www.apache.org/licenses/LICENSE-2.0\\n#\\n# Unless required by applicable law or agreed to in writing, software\\n# distributed under the License is distributed on an \\\"AS IS\\\" BASIS,\\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\\n# See the License for the specific language governing permissions and\\n# limitations under the License.\\n\\npackage.access=sun.,org.apache.catalina.,org.apache.coyote.,org.apache.jasper.,org.apache.tomcat.\\npackage.definition=sun.,java.,org.apache.catalina.,org.apache.coyote.,