nitored resources. If one of these changes, the    -->\\n    <!-- web application will be reloaded.                                   -->\\n    <WatchedResource>WEB-INF/web.xml</WatchedResource>\\n    <WatchedResource>${catalina.base}/conf/web.xml</WatchedResource>\\n\\n    <Loader delegate=\\\"true\\\" />\\n    <!-- Uncomment this to disable session persistence across Tomcat restarts -->\\n    <!--\\n    <Manager pathname=\\\"\\\" />\\n    -->\\n</Context>\", \"mount_path\": \"/usr/local/tomcat/conf/context.xml\"}, {\"content\": \"\\nrest.ishttps=false\\nrest.server.ip=http://macc-servce:8080\\n\\nrest.appid=web0f8c14945d244\\nrest.secret=5a3a3e79e71e48b5973adb37cc6e5dd4\\n\\nrview.appid=maccf2b2ss9ffa6scjh\\nrview.secret=asdfff1c69534c9ca8d1fss6e7cjsoa\\n\\ncloudprint.appid=cloudprint\\ncloudprint.secret=cloudprint\\n\\nrest.nocio.ip=https://cloud-ltt.rj.link\\n\\nisPublicCloud=0\\nrest.server.url=/service/api/\\nrest.enetServer.ip = http://macc-service:8080\\nrest.enetServer.url = /api/v1/um/\\n\\nrest.inspection.ip=http://macc-logbiz-agent:8080\\nrest.inspection.url=/logbizagent/inspection/api/\\n\\nrest.stamgt.ip=http://macc-service:8080\\nrest.stamgt.url=/logbizagent/logbiz/api/\\n\\ncommnity.appid=intelligentcommunity\\ncommnity.secret=intelligentcommunity\\n\\n#\\\\u56fd\\\\u9645\\\\u5316\\\\u914d\\\\u7f6e\\\\uff0c\\\\u8d44\\\\u6e90\\\\u6587\\\\u4ef6\\\\u524d\\\\u7f00\\nconfig.i18n.filePrefix=message\\n#cookie\\\\u6700\\\\u5927\\\\u65f6\\\\u95f4 3600 * 24 * 15 = 12960000 \\\\u79d2 = 15 \\\\u5929\\nconfig.maxAge=12960000\\n\\nmacc.appid=web0f8c14945d244\\nmacc.secret=5a3a3e79e71e48b5973adb37cc6e5dd4\\n\\nrest.interalprotalsever.ip=http://macc-service:8080\\nrest.interalprotalsever.url=/open/service\\nrest.interalprotalsever.authenticator=EDYWVM3JKGTC\\nrest.interalprotalsever.desKey=TE4L6BAZ5DCOMGASE3M3ZIKV\\n\\nrest.weixin.domain=http://cloud-ltt.rj.link\", \"mount_path\": \"/usr/local/tomcat/macc_conf/admin_init.properties\"}, {\"content\": \"\\nlogging:\\n