pages/base/register/register2.html\\n\\n#add at Tue May 9 14:17:10 CST 2017\\nrest.weixin.domain=http://cloud-ltt.rj.link\\n\\nmacc.appid=web0f8c14945d244\\nmacc.secret=5a3a3e79e71e48b5973adb37cc6e5dd4\\n\\n#macc.noclab.nbmaint.managerServer.host=http://maccdemo.ruijie.com.cn:50088\\n#macc.noclab.nbmaint.managerServer.api.upgrade.sync.version=2017121501\", \"mount_path\": \"/usr/local/tomcat/macc_conf/macc3/macc3_init.properties\"}, {\"content\": \"\\nsso.isopen=true\\n\\nsso.server.name=https://cloud-ltt.rj.link\\nmacc.server.name=https://cloud-ltt.rj.link\\n\\n\\nsso.logouturl=${sso.server.name}/sso/logout?service=${macc.server.name}/admin3\\n\\ncasServerUrlPrefix=${sso.server.name}/sso\\ncasServerLoginUrl=${sso.server.name}/sso/login\\n\\nignorePattern=.png|.jpg|.css|.gif|.js|/maccindex2|/login/register|/res|/login/exit|/activity|/login/debug\", \"mount_path\": \"/usr/local/tomcat/macc_conf/macc3/macc3_sso.properties\"}, {\"content\": \"\\n which cache used\\naliyun.accessKeyId=LTAIPjo7geM3lqvl\\naliyun.accessKeySecret=Gnlj6IulKq8gWvDWRKl6Ltt8pl9bJM\\naliyun.appKey=FFFF0N0N000000007159\\naliyun.captcha.scene=1gy2fy9v\\naliyun.captcha.prefix=1upv3l\", \"mount_path\": \"/usr/local/tomcat/macc_conf/properties/aliyun.properties\"}, {\"content\": \"\\n# which cache used\\nredis.host-name=redis.cloud.io\\nredis.password=Ll#2t6Cow@d\\nredis.port=6379\\nredis.maxIdle=25\\nredis.maxTotal=200\\nredis.minIdle=10\\n#max wait in ms\\nredis.maxWaitMillis=2000\\nredis.testOnBorrow=false\\nredis.testOnReturn=false\\nredis.testWhileIdle=true\\nredis.minEvictableIdleTimeMillis=60000\\nredis.timeBetweenEvictionRunsMillis=300000\\n\\n#redis-cluster sentinel config\\nredis.sentinel.masterName=maccredismaster\\nredis.sentinel1.host=10.111.20.1\\nredis.sentinel1.port=26379\\nredis.sentinel2.host=10.111.20.2\\nredis.sentinel2.port=26380\\nredis.sentinel3.host=10.111.20.2\\nredis.sentinel3.port=26381\", \"mount_path\": \"/usr/local/tomcat/macc_conf/properties/cache.properties\"}, {\"content\": \"\\n#\\n# Licensed to Jasig under one or more contributor license\\n# agreements. See the NOTICE file distributed with this work\\n# for additional information regarding copyright ownership.\\n# Jasig licenses this file to you under the Apache License,\\n# Version 2.0 (the \\\"License\\\"); you may not use this file\\n# except in compliance with the License.  You may obtain a\\n# copy of the License at the following location:\\n#\\n#   http://www.apache.org/licenses/LICENSE-2.0\\n#\\n# Unless required by applicable law or agreed to in writing,\\n# software distributed under the License is distributed on an\\n# \\\"AS IS\\\" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\\n# KIND, either express or implied.  See the License for the\\n# specific language governing permissions and limitations\\n# under the License.\\n#\\n# locale value : zh_CN or en\\ncas.locale=zh_CN\\n\\ncas.ishttps=false\\nserver.name=https://cloud-ltt.rj.link\\nmacc.server.name=https://cloud-ltt.rj.link\\nrest.server.ip=http://macc-service:8080\\n\\nmacc.login.sign.secret=b097c389-d722-4e43-8e89-35f4276db9c7\\n#web login appid\\nlogin.appid=web0f8c14945d244\\nlogin.secret=5a3a3e79e71e48b5973adb37cc6e5dd4\\n\\nmacc.demo.username=demo\\nmacc.demo.password=admin1234\\n\\n# api publickey\\napiserver.encrypt.\\napiserver.rsa128.encrypt.publickey=MIGfMA0GCSqGSIb3DQEBAQUAA4GNADCBiQKBgQCBHM8FrCEAkRDv/HBnWzDPz3LPn2MHHttnuJJEbUdhWBO0Cp/MmyKVJtoQgdlgthND3ThsPox2uYmZBxNzeSPLNwfJhKJX34NVF2oU4fmzkhFHlU8mAsBsruhcmGzAncOnm4Q1H+y671oKXLokd2g5N4aSM6o61xmCnDI0s7s3DwIDAQAB\\n\\n# weixin login\\nwx.domain=https://cloud-ltt.rj.link\\nwx.appid=wx5261cf07d729f630\\nwx.secret=a88cf5e85519544f33faa0772a2fdc02\\n\\ncas.client.permitAddress=http\\\\://127.0.0.0\\n# sso server address\\nserver.prefix=${server.name}/sso\\n# macc server address\\nmacc.server=${macc.server.name}/admin\\n\\ndefault.macc.version=3\\n#macc3.redirect.url=${macc.server.name}/macc5/admin/\\n#macc3.redirect.url=${macc.server.name}/admin3/\\nmacc3.redirect.url=https://cloud-ltt.rj.link/webproxy/sso/back?rewrite=off&back=https%3A%2F%2Fcloud-ltt.rj.link%2Fmacc5%2Fadmin%2F%23%2F\\nmacc.redirect.url=${macc.server.name}/admin/redictIndex\\n\\n# Spring Security\'s EL-based access rules for the /status URI of CAS that exposes health check information\\ncas.securityContext.status.access=permitAll\\n\\n# Spring Security\'s EL-based access rules for the /statistics URI of CAS that exposes stats about the CAS server\\ncas.securityContext.statistics.access=hasIpAddress(\'127.0.0.1\')\\n\\ncas.themeResolver.defaultThemeName=cas-theme-default\\n\\n# Path prefix for where views are to be found\\n# cas.viewResolver.defaultViewsPathPrefix=/WEB-INF/view/jsp/default/ui/\\n\\n# Location of the Spring xml config file where views may be collected\\n# cas.viewResolver.xmlFile=/META-INF/spring/views.xml\\n\\n##\\n# Unique CAS node name\\n# host.name is used to generate unique Service Ticket IDs and SAMLArtifacts.  This is usually set to the specific\\n# hostname of the machine running the CAS node, but it could be any label so long as it is unique in the cluster.\\nhost.name=macc1.ruijie.com.cn-server-A\\n\\n##\\n# Database flavors for Hibernate\\n#\\n# One of these is needed if you are storing Services or Tickets in an RDBMS via JPA.\\n#\\n# database.hibernate.dialect=org.hibernate.dialect.OracleDialect\\n# database.hibernate.dialect=org.hibernate.dialect.MySQLInnoDBDialect\\n# database.hibernate.dialect=org.hibernate.dialect.HSQLDialect\\n# database.hibernate.batchSize=10\\n\\n##\\n# CAS SSO Cookie Generation & Security\\n# See https://github.com/mitreid-connect/json-web-key-generator\\n#\\n# Do note that the following settings MUST be generated per deployment.\\n#\\n# Defaults at spring-configuration/ticketGrantingTicketCookieGenerator.xml\\n# The encryption secret key. By default, must be a octet string of size 256.\\ntgc.encryption.key=1PbwSbnHeinpkZOSZjuSJ8yYpUrInm5aaV18J2Ar4rM\\n\\n# The signing secret key. By default, must be a octet string of size 512.\\ntgc.signing.key=szxK-5_eJjs-aUj-64MpUZ-GPPzGLhYPLGl0wrYjYNVAGva2P0lLe6UGKGM7k8dWxsOVGutZWgvmY3l5oVPO3w\\n\\n##\\n# CAS Logout Behavior\\n# WEB-INF/cas-servlet.xml\\n#\\n# Specify whether CAS should redirect to the specified service parameter on /logout requests\\ncas.logout.followServiceRedirects=true\\n\\n##\\n# CAS Cached Attributes Timeouts\\n# Controls the cached attribute expiration policy\\n#\\n# Notes the duration in which attributes will be kept alive\\n# cas.attrs.timeToExpireInHours=2\\n\\n##\\n# Single Sign-On Session\\n#\\n# Indicates whether an SSO session should be created for renewed authentication requests.\\n# create.sso.renewed.authn=true\\n#\\n# Indicates whether an SSO session can be created if no service is present.\\n# create.sso.missing.service=true\\n\\n##\\n# Spring Webflow Web Application Session\\n# Define the settings that are required to encrypt and persist the CAS web application session.\\n# See the cas-servlet.xml file to understand how these properties are used.\\n#\\n# cas.webflow.cipher.alg=AES\\n# cas.webflow.cipher.mode=CBC\\n# cas.webflow.cipher.padding=PKCS7\\n# cas.webflow.keystore=classpath:/etc/keystore.jceks\\n# cas.webflow.keystore.type=JCEKS\\n# cas.webflow.keystore.password=changeit\\n# cas.webflow.keyalias=aes128\\n# cas.webflow.keypassword=changeit\\n##\\n# Single Sign-On Session Timeouts\\n# Defaults sourced from WEB-INF/spring-configuration/ticketExpirationPolices.xml\\n#\\n# Maximum session timeout - TGT will expire in maxTimeToLiveInSeconds regardless of usage\\n# tgt.maxTimeToLiveInSeconds=28800\\n#\\n# Idle session timeout -  TGT will expire sooner than maxTimeToLiveInSeconds if no further requests\\n# for STs occur within timeToKillInSeconds\\n tgt.timeToKillInSeconds=3600\\n\\n##\\n# Service Ticket Timeout\\n# Default sourced from WEB-INF/spring-configuration/ticketExpirationPolices.xml\\n#\\n# Service Ticket timeout - typically kept short as a control against replay attacks, default is 10s.  You\'ll want to\\n# increase this timeout if you are manually testing service ticket creation/validation via tamperdata or similar tools\\n st.timeToKillInSeconds=60\\n \\n##\\n# Http Client Settings\\n#\\n# The http client read timeout in milliseconds\\n# http.client.read.timeout=5000\\n\\n# The http client connection timeout in milliseconds\\n# http.client.connection.timeout=5000\\n#\\n# The http client truststore file, in addition to the default\'s\\n# http.client.truststore.file=classpath:truststore.jks\\n#\\n# The http client truststore\'s password\\n# http.client.truststore.psw=changeit\\n\\n##\\n# Single Logout Out Callbacks\\n# Default sourced from WEB-INF/spring-configuration/argumentExtractorsConfiguration.xml\\n#\\n# To turn off all back channel SLO requests set this to true\\n# slo.callbacks.disabled=false\\n#\\n# To send callbacks to endpoints synchronously, set this to false\\n# slo.callbacks.asynchronous=true\\n\\n##\\n# CAS Protocol Security Filter\\n#\\n# Are multi-valued parameters accepted?\\n# cas.http.allow.multivalue.params=false\\n\\n# Define the list of request parameters to examine for sanity\\n# cas.http.check.params=ticket,service,renew,gateway,warn,target,SAMLart,pgtUrl,pgt,pgtId,pgtIou,targetService\\n\\n# Define the list of request parameters only allowed via POST\\n# cas.http.allow.post.params=username,password\\n \\n##\\n# JSON Service Registry\\n#\\n# Directory location where JSON service files may be found.\\n# service.registry.config.location=classpath:services\\n\\n##\\n# Service Registry Periodic Reloading Scheduler\\n# Default sourced from WEB-INF/spring-configuration/applicationContext.xml\\n#\\n# Force a startup delay of 2 minutes.\\n# service.registry.quartz.reloader.startDelay=120000\\n#\\n# Reload services every 2 minutes\\n# service.registry.quartz.reloader.repeatInterval=120000\\n \\n##\\n# Log4j\\n# Default sourced from WEB-INF/spring-configuration/log4jConfiguration.xml:\\n#\\n# It is often time helpful to externalize log4j.xml to a system path to preserve settings between upgrades.\\n# e.g. log4j.config.location=/etc/cas/log4j.xml\\n# log4j.config.location=classpath:log4j.xml\\n \\n##\\n# Metrics\\n# Default sourced from WEB-INF/spring-configuration/metricsConfiguration.xml:\\n#\\n# Define how often should metric data be reported. Default is 30 seconds.\\n# metrics.refresh.internal=30s\\n\\n##\\n# Encoding\\n#\\n# Set the encoding to use for requests. Default is UTF-8\\n# httprequest.web.encoding=UTF-8\\n\\n# Default is true. Switch this to \\\"false\\\" to not enforce the specified encoding in any case,\\n# applying it as default response encoding as well.\\n# httprequest.web.encoding.force=true\\n\\n##\\n# Reports\\n#\\n# Setting to whether include the ticket granting ticket id in the report\\n# sso.sessions.include.tgt=false\\n\\n##\\n# Password Policy\\n#\\n# Warn all users of expiration date regardless of warningDays value.\\n# password.policy.warnAll=false\\n\\n# Threshold number of days to begin displaying password expiration warnings.\\n# password.policy.warningDays=30\\n\\n# URL to which the user will be redirected to change the password.\\n# password.policy.url=https://password.example.edu/change\", \"mount_path\": \"/usr/local/tomcat/macc_conf/properties/cas.properties\"}, {\"content\": \"\\nrest.encryption.public-key=MIGfMA0GCSqGSIb3DQEBAQUAA4GNADCBiQKBgQCBHM8FrCEAkRDv/HBnWzDPz3LPn2MHHttnuJJEbUdhWBO0Cp/MmyKVJtoQgdlgthND3ThsPox2uYmZBxNzeSPLNwfJhKJX34NVF2oU4fmzkhFHlU8mAsBsruhcmGzAncOnm4Q1H+y671oKXLokd2g5N4aSM6o61xmCnDI0s7s3DwIDAQAB\\nrest.encryption.private-\", \"mount_path\": \"/usr/local/tomcat/macc_conf/properties/encryption.properties\"}, {\"content\": \"\\ndestination=/logs\", \"mount_path\": \"/usr/local/tomcat/macc_conf/logback.properties\"}, {\"content\": \"\\ndestination=/logs\", \"mount_path\": \"/usr/local/tomcat/macc_conf/properties/logback.properties\"}, {\"content\": \"\\nsso.isopen=true\\n\\nsso.server.name=https://cloud-ltt.rj.link\\nmacc.server.name=https://cloud-ltt.rj.link\\ndeviceLicense.server.name=https://cloud-ltt.rj.link\\nppsk.server.name=https://cloud-ltt.rj.link\\nmadmin.server.name=https://cloud-ltt.rj.link\\ngatewaylicense.server.name=https://cloud-ltt.rj.link\\ninspection.server.name=https://cloud-ltt.rj.link\\nsyslog.server.name=https://cloud-ltt.rj.link\\n\\n#macc logout url\\nsso.logouturl=${sso.server.name}/sso/logout?service=${macc.server.name}/nocindex/\\n#admin/maccindex\\n#deviceLicense logout url\\ndeviceLicense.sso.logouturl=${sso.server.name}/sso/logout?service=${deviceLicense.server.name}/admin/maccindex\\n\\ncasServerUrlPrefix=${sso.server.name}/sso\\ncasServerLoginUrl=${sso.server.name}/sso/login\\n\\n#macc ignorePattern\\nignorePattern=.png|.jpg|.css|.gif|.js|.jpeg|.svg|.ico|/res|/help|/maccindex|/ewebdiagnose|/activity/recommendsignup|/login/exit|/monitor/getReportFile\\n#deviceLicense ignorePattern\\ndeviceLicense.ignorePattern=.png|.jpg|.jpeg|.css|.gif|.js\\nppsk.ignorePattern=.png|.jpg|.jpeg|.css|.gif|.js\", \"mount_path\": \"/usr/local/tomcat/macc_conf/sso.properties\"}], \"limit_memory\": \"4Gi\"}]}','2026-06-28 14:42:38.796137','2026-06-29 10:43:35.211834');
